import sys

data = list(map(int, sys.stdin.read().split()))
n, target = data[0], data[1]
nums = data[2:2 + n]
left, right = 0, n - 1

while left <= right:
    mid = (left + right) // 2
    if nums[mid] == target:
        print(mid)
        break
    if nums[mid] < target:
        left = mid + 1
    else:
        right = mid - 1
else:
    print(-1)
